image:image:
  records for Google Image Search (social card or speaker photo).
-#}
{%- set seo = bag('seo') -%}
{%- set noindex_paths = seo['noindex_paths'] -%}

  {%- for page in [site.root] if page != this and page.url_path not in noindex_paths recursive %}

    {{ page|url(external=true) }}
    {%- set lastmod = page['pub_date'] or page['created'] %}
    {%- if lastmod %}
    {{ lastmod }}
    {%- endif %}
    {%- if page['social_card_image'] %}

      {{ site.config.PROJECT.url }}{{ page['social_card_image'] }}
      {{ page['title']|striptags|e }}

    {%- endif %}
    {%- if page['youtube_id'] and not page['do_not_record'] %}

      {{ page['video_thumbnail'] or ('https://i.ytimg.com/vi/' ~ page['youtube_id'] ~ '/maxresdefault.jpg') }}
      {{ page['title']|striptags|e }}
      {{ (page['abstract'] or page['description'] or '')|striptags|truncate(2000)|e }}
      {{ page['video_link'] or ('https://www.youtube.com/watch?v=' ~ page['youtube_id']) }}
      https://www.youtube-nocookie.com/embed/{{ page['youtube_id'] }}
      {%- if page['video_published_at'] %}
      {{ page['video_published_at'] }}
      {%- endif %}
      {%- if page['video_duration_iso'] %}
      {{ page['video_duration_iso']|replace('PT','')|replace('H',':')|replace('M',':')|replace('S','') }}
      {%- endif %}
      yes

    {%- endif %}

  {{- loop(page.children|sort(attribute='path')) }}
  {%- endfor %}
